29	// Foundry colophons (global — no nameplate imprint)
30	pub const RBTDRM_COLOPHON_ORDAIN: &str = "rbw-fO";
31	pub const RBTDRM_COLOPHON_ABJURE: &str = "rbw-fA";
32	pub const RBTDRM_COLOPHON_TALLY: &str = "rbw-ft";
33	pub const RBTDRM_COLOPHON_KLUDGE: &str = "rbw-fk";
34	pub const RBTDRM_COLOPHON_VOUCH: &str = "rbw-fV";
35	pub const RBTDRM_COLOPHON_SUMMON: &str = "rbw-fs";
36	pub const RBTDRM_COLOPHON_PLUMB_FULL: &str = "rbw-fpf";
37	pub const RBTDRM_COLOPHON_PLUMB_COMPACT: &str = "rbw-fpc";
38	
39	// Image colophons (global — no nameplate imprint)
40	// Three-domain symmetric: hallmarks (h), reliquaries (r), enshrinements (e).
41	// Verbs: rekon (member-list), muster (catalog-list), Jettison (delete), wrest (pull).
42	pub const RBTDRM_COLOPHON_REKON_HALLMARK: &str = "rbw-irh";
43	pub const RBTDRM_COLOPHON_REKON_RELIQUARY: &str = "rbw-irr";
44	pub const RBTDRM_COLOPHON_MUSTER_HALLMARKS: &str = "rbw-imh";
45	pub const RBTDRM_COLOPHON_MUSTER_RELIQUARIES: &str = "rbw-imr";
46	pub const RBTDRM_COLOPHON_MUSTER_ENSHRINEMENTS: &str = "rbw-ime";
47	pub const RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE: &str = "rbw-iwh";
48	pub const RBTDRM_COLOPHON_WREST_RELIQUARY_IMAGE: &str = "rbw-iwr";
49	pub const RBTDRM_COLOPHON_WREST_ENSHRINED_IMAGE: &str = "rbw-iwe";
