58	pub const RBTDRM_COLOPHON_ACCESS_PROBE: &str = "rbtd-ap";
59	
60	// Handbook display colophons — one symbolic ref per RBZ_* zipper constant.
61	// Onboarding group (8)
62	pub const RBTDRM_COLOPHON_ONBOARD_START_HERE: &str = "rbw-o";
63	pub const RBTDRM_COLOPHON_ONBOARD_CRASH_COURSE: &str = "rbw-Occ";
64	pub const RBTDRM_COLOPHON_ONBOARD_CRED_RETRIEVER: &str = "rbw-Ocr";
65	pub const RBTDRM_COLOPHON_ONBOARD_CRED_DIRECTOR: &str = "rbw-Ocd";
66	pub const RBTDRM_COLOPHON_ONBOARD_FIRST_CRUCIBLE: &str = "rbw-Ofc";
67	pub const RBTDRM_COLOPHON_ONBOARD_DIR_FIRST_BUILD: &str = "rbw-Odf";
