76	pub const RBTDRM_COLOPHON_PAYOR_ESTABLISH: &str = "rbw-gPE";
77	pub const RBTDRM_COLOPHON_PAYOR_REFRESH: &str = "rbw-gPR";
78	pub const RBTDRM_COLOPHON_QUOTA_BUILD: &str = "rbw-gq";
