80	// Fixture name consts — single definition per String Boundary Discipline.
81	// Crucible fixtures (charge/quench lifecycle)
82	pub const RBTDRM_FIXTURE_TADMOR: &str = "tadmor";
83	pub const RBTDRM_FIXTURE_SRJCL: &str = "srjcl";
84	pub const RBTDRM_FIXTURE_PLUML: &str = "pluml";
85	// Bare fixtures (GCP credentials, no container runtime)
86	pub const RBTDRM_FIXTURE_FOUR_MODE: &str = "four-mode";
87	pub const RBTDRM_FIXTURE_BATCH_VOUCH: &str = "batch-vouch";
88	pub const RBTDRM_FIXTURE_ACCESS_PROBE: &str = "access-probe";
89	// Fast fixtures (no external dependencies)
90	pub const RBTDRM_FIXTURE_ENROLLMENT_VALIDATION: &str = "enrollment-validation";
91	pub const RBTDRM_FIXTURE_REGIME_VALIDATION: &str = "regime-validation";
92	pub const RBTDRM_FIXTURE_REGIME_SMOKE: &str = "regime-smoke";
