95	/// Per-fixture required colophons. Returns None for unknown fixtures.
96	pub fn rbtdrm_required_colophons(fixture: &str) -> Option<&'static [&'static str]> {
97	    match fixture {
98	        RBTDRM_FIXTURE_TADMOR | RBTDRM_FIXTURE_SRJCL | RBTDRM_FIXTURE_PLUML => Some(&[
99	            RBTDRM_COLOPHON_CHARGE,
100	            RBTDRM_COLOPHON_QUENCH,
101	            RBTDRM_COLOPHON_WRIT,
102	            RBTDRM_COLOPHON_FIAT,
103	            RBTDRM_COLOPHON_BARK,
104	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
105	        ]),
106	        RBTDRM_FIXTURE_FOUR_MODE => Some(&[
107	            RBTDRM_COLOPHON_ORDAIN,
108	            RBTDRM_COLOPHON_ABJURE,
109	            RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE,
110	            RBTDRM_COLOPHON_KLUDGE,
111	            RBTDRM_COLOPHON_SUMMON,
112	            RBTDRM_COLOPHON_PLUMB_FULL,
113	            RBTDRM_COLOPHON_PLUMB_COMPACT,
114	            RBTDRM_COLOPHON_REKON_HALLMARK,
115	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
116	        ]),
117	        RBTDRM_FIXTURE_BATCH_VOUCH => Some(&[
118	            RBTDRM_COLOPHON_ORDAIN,
119	            RBTDRM_COLOPHON_ABJURE,
120	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
121	            RBTDRM_COLOPHON_VOUCH,
122	            RBTDRM_COLOPHON_TALLY,
123	        ]),
124	        RBTDRM_FIXTURE_ACCESS_PROBE => Some(&[RBTDRM_COLOPHON_ACCESS_PROBE]),
125	        RBTDRM_FIXTURE_ENROLLMENT_VALIDATION
126	        | RBTDRM_FIXTURE_REGIME_VALIDATION
127	        | RBTDRM_FIXTURE_REGIME_SMOKE => Some(&[]),
128	        RBTDRM_FIXTURE_HANDBOOK_RENDER => Some(&[
129	            RBTDRM_COLOPHON_ONBOARD_START_HERE,
130	            RBTDRM_COLOPHON_ONBOARD_CRASH_COURSE,
131	            RBTDRM_COLOPHON_ONBOARD_CRED_RETRIEVER,
132	            RBTDRM_COLOPHON_ONBOARD_CRED_DIRECTOR,
133	            RBTDRM_COLOPHON_ONBOARD_FIRST_CRUCIBLE,
134	            RBTDRM_COLOPHON_ONBOARD_DIR_FIRST_BUILD,
135	            RBTDRM_COLOPHON_ONBOARD_PAYOR_HB,
136	            RBTDRM_COLOPHON_ONBOARD_GOVERNOR_HB,
137	            RBTDRM_COLOPHON_HANDBOOK_TOP,
138	            RBTDRM_COLOPHON_HANDBOOK_WINDOWS,
139	            RBTDRM_COLOPHON_HW_DOCKER_DESKTOP,
140	            RBTDRM_COLOPHON_HW_DOCKER_CONTEXT,
141	            RBTDRM_COLOPHON_PAYOR_ESTABLISH,
142	            RBTDRM_COLOPHON_PAYOR_REFRESH,
143	            RBTDRM_COLOPHON_QUOTA_BUILD,
144	        ]),
145	        _ => None,
146	    }
147	}
148	
149	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
150	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
151	    let required = match rbtdrm_required_colophons(fixture) {
152	        Some(r) => r,
153	        None => {
154	            return Err(format!(
155	                "rbtd: unknown fixture '{}' — not registered in manifest",
156	                fixture
157	            ));
158	        }
159	    };
160	    for colophon in required {
161	        let found = manifest.split_whitespace().any(|token| token == *colophon);
162	        if !found {
163	            return Err(format!(
164	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
165	                colophon, fixture
166	            ));
167	        }
168	    }
169	    Ok(())
170	}
