14	//
15	// Author: Brad Hyslop <bhyslop@scaleinvariant.org>
16	//
17	// RBTD Theurge — test orchestrator entry point
18	//
19	// Subcommands:
20	//   rbtd <manifest> <fixture>
21	//     Suite runner — verify manifest, charge, run all cases, quench.
22	//   rbtd single <manifest> <fixture> [case]
23	//     Single-case runner — no charge/quench. List cases or run one.
24	
25	use std::process::ExitCode;
26	
27	use rbtd::rbtdrc_crucible::{
28	    rbtdrc_needs_charge, rbtdrc_needs_readiness_delay, rbtdrc_sections_for_fixture,
29	    rbtdrc_set_context, rbtdrc_take_context, RBTDRC_SERVICE_READINESS_DELAY_SECS,
30	};
31	use rbtd::rbtdre_engine::{
32	    rbtdre_detect_colors, rbtdre_find_case, rbtdre_list_cases, rbtdre_print_summary,
33	    rbtdre_run_sections, rbtdre_run_single_case,
34	};
35	use rbtd::rbtdri_invocation::{rbtdri_Context, rbtdri_invoke, rbtdri_invoke_global};
36	use rbtd::rbtdrm_manifest::{
37	    rbtdrm_verify, RBTDRM_COLOPHON_CHARGE, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
38	    RBTDRM_COLOPHON_QUENCH,
39	};
40	
41	fn main() -> ExitCode {
42	    let args: Vec<String> = std::env::args().collect();
43	
44	    if args.get(1).map(|s| s.as_str()) == Some("single") {
45	        return run_single(&args[2..]);
46	    }
47	
48	    run_suite(&args[1..])
49	}
50	
51	// ── Suite runner ─────────────────────────────────────────────
52	
53	fn run_suite(args: &[String]) -> ExitCode {
54	    let manifest = match args.first() {
55	        Some(m) => m,
56	        None => {
57	            eprintln!(
58	                "rbtd: usage: rbtd <manifest> <fixture>\n\
59	                 theurge must be launched via tabtarget (e.g. tt/rbtd-r.Run.tadmor.sh)"
60	            );
61	            return ExitCode::FAILURE;
62	        }
63	    };
64	
65	    let fixture = match args.get(1) {
66	        Some(n) => n,
67	        None => {
68	            eprintln!("rbtd: no fixture argument — which test fixture to run?");
69	            return ExitCode::FAILURE;
70	        }
71	    };
72	
73	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
74	        eprintln!("{}", msg);
75	        return ExitCode::FAILURE;
76	    }
77	
78	    let project_root = match std::env::current_dir() {
79	        Ok(p) => p,
80	        Err(e) => {
81	            eprintln!("rbtd: cannot determine working directory: {}", e);
82	            return ExitCode::FAILURE;
83	        }
84	    };
85	
