266	/// Ifrit verdict wire protocol: ifrit prints exactly one line matching
267	/// `IFRIT_VERDICT: PASS` or `IFRIT_VERDICT: FAIL <detail>` to stdout.
268	/// Missing verdict line is always a failure — no silent pass-through.
269	pub fn rbtdri_parse_ifrit_verdict(stdout: &str, exit_code: i32) -> rbtdre_Verdict {
270	    for line in stdout.lines() {
271	        let trimmed = line.trim();
272	        if let Some(rest) = trimmed.strip_prefix("IFRIT_VERDICT:") {
273	            let rest = rest.trim();
274	            if rest.starts_with("PASS") {
275	                return rbtdre_Verdict::Pass;
276	            }
277	            if let Some(detail) = rest.strip_prefix("FAIL") {
278	                let detail = detail.trim();
279	                if detail.is_empty() {
280	                    return rbtdre_Verdict::Fail("ifrit reported failure".to_string());
281	                }
282	                return rbtdre_Verdict::Fail(detail.to_string());
283	            }
284	        }
285	    }
286	
287	    if exit_code == 0 {
288	        rbtdre_Verdict::Fail("ifrit exited 0 but no verdict line found".to_string())
289	    } else {
290	        rbtdre_Verdict::Fail(format!("ifrit exited {} with no verdict line", exit_code))
291	    }
292	}
