            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
        ]),
        RBTDRM_FIXTURE_BATCH_VOUCH => Some(&[
            RBTDRM_COLOPHON_ORDAIN,
            RBTDRM_COLOPHON_ABJURE,
            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
            RBTDRM_COLOPHON_VOUCH,
            RBTDRM_COLOPHON_TALLY,
